// nodes/outputNode.js
import { BaseNode } from './BaseNode';
import { ArrowLeftCircle } from 'lucide-react';

export const OutputNode = ({ id, data, selected }) => {
  return (
    <BaseNode
      id={id}
      title="Output"
      icon={ArrowLeftCircle}
      accentColor="var(--accent-emerald)"
      inputs={[{ id: 'value', label: 'value' }]}
      selected={selected}
    >
      <div style={{ fontSize: '13px', color: 'var(--text-secondary)' }}>
        <span style={{ fontWeight: 500, color: 'var(--text-primary)' }}>{data?.outputName || id.replace('customOutput-', 'output_')}</span>
        <div style={{ fontSize: '11px', marginTop: 4, color: 'var(--text-tertiary)' }}>Type: {data?.outputType || 'Text'}</div>
      </div>
    </BaseNode>
  );
};
